use std::sync::{Arc, Mutex};
use std::thread;

struct Inventory {
    stock: i32,
}

impl Inventory {
    fn new(stock: i32) -> Self {
        Inventory { stock }
    }

    fn update_stock(&mut self, amount: i32) -> Result<(), &'static str> {
        if self.stock >= amount {
            self.stock -= amount;
            Ok(())
        } else {
            Err("Insufficient stock")
        }
    }
}

fn main() {
    let inventory = Arc::new(Mutex::new(Inventory::new(100)));
    let mut handles = vec![];

    for _ in 0..10 {
        let inventory_clone = Arc::clone(&inventory);
        let handle = thread::spawn(move || {
            let mut inv = inventory_clone.lock().unwrap();
            match inv.update_stock(10) {
                Ok(_) => println!("Stock updated successfully"),
                Err(e) => println!("Failed to update stock: {}", e),
            }
        });
        handles.push(handle);
    }

    for handle in handles {
        handle.join().unwrap();
    }

    let final_stock = inventory.lock().unwrap().stock;
    println!("Final stock level: {}", final_stock);
}